sql:
SELECT priority_name, description, created_at, updated_at
FROM priority_levels
WHERE priority_name = 'High';

external_knowledge:
- "Revisited at least once" refers to having more than zero status changes (`COUNT(th.history_id) > 0`);
- "The start of the new year" refers to January 1, 2023;
- "The end of spring" refers to May 31, 2023.

sql:
SELECT priority_name, description, created_by, updated_by, created_at
FROM priority_levels
WHERE priority_id = 0;

SELECT priority_name, description
FROM priority_levels
WHERE priority_id = (SELECT MAX(priority_id) FROM priority_levels);

SELECT user_name
FROM users
WHERE user_id IN (
  SELECT created_by
  FROM priority_levels
);
